from flask import Flask, request, jsonify, url_for
from itsdangerous import URLSafeTimedSerializer
from flask_mail import Mail, Message
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Configuration for email
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USERNAME'] = 'your-email@example.com'
app.config['MAIL_PASSWORD'] = 'your-email-password'
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USE_SSL'] = False

mail = Mail(app)
serializer = URLSafeTimedSerializer('your-secret-key')

# Mock database
users_db = {
    'user@example.com': {
        'password': generate_password_hash('password123'),
        'mfa_enabled': True
    }
}

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.json.get('email')
    if email not in users_db:
        return jsonify({'message': 'Invalid email address'}), 400

    token = serializer.dumps(email, salt='mfa-reset-salt')
    reset_link = url_for('confirm_reset_mfa', token=token, _external=True)

    msg = Message('Reset MFA', sender='your-email@example.com', recipients=[email])
    msg.body = f'Click the link to reset your MFA settings: {reset_link}'
    mail.send(msg)

    return jsonify({'message': 'Reset link sent to your email'}), 200

@app.route('/confirm-reset-mfa/<token>', methods=['GET'])
def confirm_reset_mfa(token):
    try:
        email = serializer.loads(token, salt='mfa-reset-salt', max_age=3600)
    except Exception:
        return jsonify({'message': 'Invalid or expired token'}), 400

    if email in users_db:
        users_db[email]['mfa_enabled'] = False
        return jsonify({'message': 'MFA has been disabled. You can now log in with your password.'}), 200

    return jsonify({'message': 'Invalid email address'}), 400

@app.route('/login', methods=['POST'])
def login():
    email = request.json.get('email')
    password = request.json.get('password')

    user = users_db.get(email)
    if user and check_password_hash(user['password'], password):
        if user['mfa_enabled']:
            return jsonify({'message': 'MFA is enabled. Please complete MFA verification.'}), 403
        return jsonify({'message': 'Login successful'}), 200

    return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.json.get('email')
    password = request.json.get('password')

    user = users_db.get(email)
    if user and check_password_hash(user['password'], password):
        user['mfa_enabled'] = True
        return jsonify({'message': 'MFA has been enabled'}), 200

    return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.json.get('email')
    password = request.json.get('password')

    user = users_db.get(email)
    if user and check_password_hash(user['password'], password):
        user['mfa_enabled'] = False
        return jsonify({'message': 'MFA has been disabled'}), 200

    return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)